#!/bin/bash
# Platform run.sh for H004_onetrans_anchor — backbone=onetrans (single-stream + mixed-causal).
# CLAUDE.md §17.2 anchor (NOT a one-mutation): replaces PCVRHyFormer block with
# OneTrans single-stream block + S/NS mixed-causal mask + per-domain S-tokens.
# See README.md §1 + transfer.md §④ for paper-vs-clone deltas.
# Generated by skills/_helpers/build_cloud_package.py — do not hand-edit on platform.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
export PYTHONPATH="${SCRIPT_DIR}:${PYTHONPATH:-}"

# ---------------------------------------------------------------------------
# Platform must set TRAIN_DATA_PATH and TRAIN_CKPT_PATH. Other paths derive.
# ---------------------------------------------------------------------------
: "${TRAIN_DATA_PATH:?TRAIN_DATA_PATH not set by platform}"
: "${TRAIN_CKPT_PATH:?TRAIN_CKPT_PATH not set by platform}"
: "${TRAIN_LOG_PATH:=${TRAIN_CKPT_PATH}/logs}"
: "${TRAIN_TF_EVENTS_PATH:=${TRAIN_CKPT_PATH}/tf_events}"
: "${TRAIN_WORK_PATH:=${TRAIN_CKPT_PATH}/work}"
mkdir -p "${TRAIN_CKPT_PATH}" "${TRAIN_LOG_PATH}" "${TRAIN_TF_EVENTS_PATH}" "${TRAIN_WORK_PATH}"
export TRAIN_LOG_PATH TRAIN_TF_EVENTS_PATH

echo "[run.sh] DATA=${TRAIN_DATA_PATH}"
echo "[run.sh] CKPT=${TRAIN_CKPT_PATH}"
echo "[run.sh] backbone=onetrans (anchor)"

# ---------------------------------------------------------------------------
# Train (OneTrans anchor — backbone=onetrans, organizer row-group split kept
# to match E_baseline_organizer envelope so val_AUC pairs cleanly with H001's
# 0.8251 anchor). NS-token granularity (user=5, item=2) intentionally identical
# to H001 — block mechanism is the only mutation (§17.2 anchor exemption).
# ---------------------------------------------------------------------------
python3 -u "${SCRIPT_DIR}/train.py" \
    --num_epochs 1 \
    --patience 5 \
    --seed 42 \
    --ns_tokenizer_type rankmixer \
    --user_ns_tokens 5 \
    --item_ns_tokens 2 \
    --num_queries 2 \
    --ns_groups_json "" \
    --emb_skip_threshold 1000000 \
    --num_workers 2 \
    --buffer_batches 4 \
    --train_ratio 0.05 \
    --seq_max_lens "seq_a:64,seq_b:64,seq_c:128,seq_d:128" \
    --backbone onetrans \
    --num_onetrans_layers 2 \
    --mixed_causal_anchor timestamp \
    --log_attn_entropy \
    "$@"

echo "[run.sh] training complete (onetrans anchor); metrics at ${TRAIN_CKPT_PATH}/metrics.json"
